num1 = float(input('请输入第一个数字：'))
num2 = float(input('请输入第二个数字：'))
operator = input('请输入运算符(+, -, *, /)：')

if operator == '+':
    result = num1 + num2
elif operator == '-':
    result = num1 - num2
elif operator == '*':
    result = num1 * num2
elif operator == '/':
    if num2 != 0:
        result = num1 / num2
    else:
        result = '除数不能为零'
else:
    result = '无效的运算符'

print('计算结果：', result)

