exercises.exampleCode:
import random

number = random.randint(1, 100)
chances = 5

print('猜数字游戏开始！数字在1-100之间，你有5次机会。')

for i in range(chances):
    guess = int(input(f'第{i+1}次猜测：'))

    if guess == number:
        print('恭喜你，猜对了！')
        break
    elif guess < number:
        print('猜小了')
    else:
        print('猜大了')
else:
    print(f'游戏结束，正确答案是：{number}')

